#!/usr/bin/env bash
# External/mbedtls/build_dolphin.sh
# Cross-compile mbedTLS static archives for Wii or GameCube using devkitPPC.
#
# Prereq: mbedTLS source must be vendored — `library/` and `include/` should
# both exist alongside this script. See External/mbedtls/README.md.
#
# Usage:
#   ./build_dolphin.sh wii   # → External/mbedtls/lib-wii/{libmbedtls,libmbedx509,libmbedcrypto}.a
#   ./build_dolphin.sh gcn   # → External/mbedtls/lib-gcn/...

set -euo pipefail

if [ -z "${DEVKITPRO:-}" ] || [ -z "${DEVKITPPC:-}" ]; then
    echo "DEVKITPRO / DEVKITPPC must be set. Install wii-dev via devkitPro pacman." >&2
    exit 1
fi

TARGET="${1:-wii}"

case "$TARGET" in
    wii)
        # Wii: PowerPC 750, EABI, hardfloat. Same flags Engine/Makefile_Wii uses.
        MACHFLAGS="-mcpu=750 -meabi -mhard-float -DPLATFORM_WII=1 -DPLATFORM_DOLPHIN=1"
        OUTDIR="lib-wii"
        ;;
    gcn)
        MACHFLAGS="-mcpu=750 -meabi -mhard-float -DPLATFORM_GAMECUBE=1 -DPLATFORM_DOLPHIN=1"
        OUTDIR="lib-gcn"
        ;;
    *)
        echo "usage: $0 [wii|gcn]" >&2
        exit 2
        ;;
esac

cd "$(dirname "$0")"

if [ ! -d library ] || [ ! -d include/mbedtls ]; then
    echo "mbedTLS source not vendored yet. See External/mbedtls/README.md for the clone steps." >&2
    exit 3
fi

# Plant the user config inside include/mbedtls/ if it isn't there yet.
# build_dolphin.sh tells the compiler to #include
# "mbedtls/polyphase_mbedtls_user_config.h", which mbedTLS resolves through
# its -I../include search path. The committed copy of this file lives next to
# this script as a .template so vendoring (which overwrites include/mbedtls/
# wholesale) doesn't blow it away.
USER_CFG_DST="include/mbedtls/polyphase_mbedtls_user_config.h"
USER_CFG_SRC="polyphase_mbedtls_user_config.h.template"
if [ ! -f "$USER_CFG_DST" ]; then
    if [ ! -f "$USER_CFG_SRC" ]; then
        echo "Missing $USER_CFG_SRC — can't seed user config. Re-pull build_dolphin.sh's sibling files." >&2
        exit 6
    fi
    echo "Seeding $USER_CFG_DST from $USER_CFG_SRC"
    cp "$USER_CFG_SRC" "$USER_CFG_DST"
fi

# library/Makefile expects sibling directories that aren't always obvious
# from the bare include + library copy. Probe for the ones it references.
if grep -q "include[[:space:]]*\.\./3rdparty/Makefile.inc" library/Makefile 2>/dev/null \
   && [ ! -d 3rdparty ]; then
    echo "library/Makefile references ../3rdparty/Makefile.inc but External/mbedtls/3rdparty is missing." >&2
    echo "Fix:" >&2
    echo "  git clone --depth 1 --branch v3.6.2 https://github.com/Mbed-TLS/mbedtls.git _clone" >&2
    echo "  mv _clone/3rdparty ./3rdparty" >&2
    echo "  rm -rf _clone" >&2
    exit 4
fi
if grep -q "include[[:space:]]*\.\./tf-psa-crypto" library/Makefile 2>/dev/null \
   && [ ! -d tf-psa-crypto ]; then
    echo "library/Makefile references ../tf-psa-crypto but External/mbedtls/tf-psa-crypto is missing." >&2
    echo "Bring it across the same way you brought 3rdparty (see README)." >&2
    exit 5
fi

# error.c, version_features.c, and a few others are auto-generated by perl
# scripts in ../scripts/. The Makefile lists them as prerequisites of the
# corresponding .c, so make tries to invoke perl + the script and fails loudly
# if scripts/ wasn't vendored.
if [ ! -d scripts ]; then
    echo "External/mbedtls/scripts is missing — library/Makefile re-generates error.c et al from this directory." >&2
    echo "Fix:" >&2
    echo "  git clone --depth 1 --branch v3.6.2 https://github.com/Mbed-TLS/mbedtls.git _clone" >&2
    echo "  mv _clone/scripts ./scripts" >&2
    echo "  rm -rf _clone" >&2
    exit 7
fi

# framework/ is a git submodule. scripts/generate_driver_wrappers.py imports
# the mbedtls_framework Python package from framework/scripts/. A plain
# `git clone --depth 1` doesn't pull submodules — easy to miss.
if [ ! -d framework/scripts/mbedtls_framework ]; then
    echo "External/mbedtls/framework is missing or empty — generate_driver_wrappers.py needs framework/scripts/mbedtls_framework/." >&2
    echo "framework/ is a git submodule and must be fetched separately." >&2
    echo "Fix:" >&2
    echo "  git clone --depth 1 --branch v3.6.2 --recurse-submodules https://github.com/Mbed-TLS/mbedtls.git _clone" >&2
    echo "  mv _clone/framework ./framework" >&2
    echo "  rm -rf _clone" >&2
    exit 10
fi

# Detect parallelism portably (nproc on Linux, NUMBER_OF_PROCESSORS on Windows
# msys2/cygwin, sysctl on macOS).
if command -v nproc >/dev/null 2>&1; then
    JOBS=$(nproc)
elif [ -n "${NUMBER_OF_PROCESSORS:-}" ]; then
    JOBS=$NUMBER_OF_PROCESSORS
elif command -v sysctl >/dev/null 2>&1; then
    JOBS=$(sysctl -n hw.ncpu 2>/dev/null || echo 4)
else
    JOBS=4
fi

# Detect Python. mbedTLS calls `python` (no version suffix) to regenerate
# psa_crypto_driver_wrappers.h. msys2 ships only `python3` by default; the
# Windows Python installer adds `py.exe`. Find whichever exists and pass it
# to make via the PYTHON variable.
PYTHON_CMD=""
for cand in python python3 py; do
    if command -v "$cand" >/dev/null 2>&1; then
        PYTHON_CMD="$cand"
        break
    fi
done
if [ -z "$PYTHON_CMD" ]; then
    echo "Python not found. Install it in msys2 with: pacman -S python" >&2
    exit 8
fi

# mbedTLS's generate_driver_wrappers.py imports jsonschema + jinja2. Probe
# them once up front rather than letting make blow up halfway through the
# compile.
MISSING_MODULES=""
for mod in jsonschema jinja2; do
    if ! "$PYTHON_CMD" -c "import $mod" >/dev/null 2>&1; then
        MISSING_MODULES="$MISSING_MODULES $mod"
    fi
done
if [ -n "$MISSING_MODULES" ]; then
    echo "Missing Python modules:$MISSING_MODULES" >&2
    echo "" >&2
    echo "Pick one of:" >&2
    echo "  A) Cleanest (msys2 package manager):" >&2
    echo "       pacman -S python-jsonschema python-jinja" >&2
    echo "  B) Project-local venv:" >&2
    echo "       $PYTHON_CMD -m venv .venv && source .venv/bin/activate && pip install$MISSING_MODULES" >&2
    echo "  C) Override PEP 668 (fast, slightly dirty):" >&2
    echo "       $PYTHON_CMD -m pip install --break-system-packages$MISSING_MODULES" >&2
    if [ -f scripts/driver.requirements.txt ]; then
        echo "" >&2
        echo "  (mbedTLS also ships a requirements file:" >&2
        echo "      $PYTHON_CMD -m pip install --break-system-packages -r scripts/driver.requirements.txt)" >&2
    fi
    exit 9
fi

PREFIX="$DEVKITPPC/bin/powerpc-eabi-"

# Tell mbedTLS to layer our user config on top of its default config. The
# escaped \" sequences are intentional — they survive shell → make → gcc so
# the compiler ultimately sees:
#   -DMBEDTLS_USER_CONFIG_FILE="mbedtls/polyphase_mbedtls_user_config.h"
# which is what mbedtls_config.h needs to #include the user override.
CFG_FLAG='-DMBEDTLS_USER_CONFIG_FILE=\"mbedtls/polyphase_mbedtls_user_config.h\"'

mkdir -p "$OUTDIR"

# Empty tests/ stub so the `static` target's post-build seedfile step (which
# does `cd ../tests && ... > seedfile`) doesn't blow up when we haven't
# vendored the test tree.
mkdir -p tests

# mbedTLS library/Makefile honours CC, AR, CFLAGS via env/args. We invoke the
# three .a targets directly rather than the `static` umbrella so we skip the
# post-build cd-to-tests recipe entirely. (mbedTLS renamed `lib` to `static`
# in 3.x; both depend on the same .a outputs.)
make -C library clean
make -C library libmbedcrypto.a libmbedx509.a libmbedtls.a \
    CC="${PREFIX}gcc" \
    AR="${PREFIX}ar" \
    PYTHON="$PYTHON_CMD" \
    CFLAGS="-O2 -ffunction-sections -fdata-sections $MACHFLAGS $CFG_FLAG" \
    -j"$JOBS"

cp library/libmbedtls.a    "$OUTDIR/"
cp library/libmbedx509.a   "$OUTDIR/"
cp library/libmbedcrypto.a "$OUTDIR/"

echo "Built mbedTLS for $TARGET → External/mbedtls/$OUTDIR/"
ls -lh "$OUTDIR/"
